  readonly billingCycle: Maybe<AdminShopify_SubscriptionBillingCycle>;
  /** The billing policy for the subscription contract. */
  readonly billingPolicy: AdminShopify_SubscriptionBillingPolicy;
  /** The billing cycles of the contracts that will be concatenated to the subscription contract. */
  readonly concatenatedBillingCycles: AdminShopify_SubscriptionBillingCycleConnection;
  /** The currency used for the subscription contract. */
  readonly currencyCode: AdminShopify_CurrencyCode;
  /** A list of the custom attributes to be added to the generated orders. */
  readonly customAttributes: ReadonlyArray<AdminShopify_Attribute>;
  /** The customer to whom the subscription contract belongs. */
  readonly customer: AdminShopify_Customer;
  /** The customer payment method used for the subscription contract. */
  readonly customerPaymentMethod: Maybe<AdminShopify_CustomerPaymentMethod>;
  /** The delivery method for each billing of the subscription contract. */
  readonly deliveryMethod: Maybe<AdminShopify_SubscriptionDeliveryMethod>;
  /** The available delivery options for a given delivery address. Returns `null` for pending requests. */
  readonly deliveryOptions: Maybe<AdminShopify_SubscriptionDeliveryOptionResult>;
  /** The delivery policy for the subscription contract. */
  readonly deliveryPolicy: AdminShopify_SubscriptionDeliveryPolicy;
  /** The delivery price for each billing the subscription contract. */
  readonly deliveryPrice: Maybe<AdminShopify_MoneyV2>;
  /** The list of subscription discounts which will be associated with the subscription contract. */
